const AUTH = "AUTH";


export type InitialStateType = {
    isAoth: boolean,
    users: any,
}
const initialState: InitialStateType = {
    isAoth: false,
    users: [],
}

const authReducer = (state = initialState, action: any) => {
    let copy;

    switch (action.type) {
        case AUTH: {
            async function api() {
                const request = await fetch("http://localhost:5000/api/users", {
                    headers: {
                        method: "GET",
                        //@ts-ignore
                        authorisation: JSON.parse(localStorage.getItem("user")).accessToken,
                    }
                })
                if (request.status === 401) {
                    console.log("Пользователь не авторизован")
                }
                const response = await request.json();
                return copy = { ...state, isAoth: action.inAuth, users: response };;
            }


            return copy;
        }
        default:
            return state = { ...initialState };
    }
};
type loginActionType = {
    type: typeof AUTH,
    inAuth: boolean,
};

export const authActin = (inAuth: boolean): loginActionType => ({
    type: AUTH,
    inAuth,
});

export default authReducer;
